```
{
  "@type": "api:InfoResponse",
  "api:info": {
    "authority": "anonymous",
    "storage": {
      "version": "1"
    },
    "terminusdb": {
      "git_hash": "53acb38f9aedeec6c524f5679965488788e6ccf5",
      "version": "10.1.5"
    },
    "terminusdb_store": {
      "version": "0.19.8"
    }
  },
  "api:status": "api:success"
}
```

